class Solution(object):
    def stringSequence(self, target):
        result = []
        current = []
        for ch in target:
            current.append('a')
            result.append(''.join(current))
            # Increment last char until it matches ch
            while current[-1] != ch:
                current[-1] = chr(ord(current[-1]) + 1)
                result.append(''.join(current))
        return result
